import { useState, useEffect } from 'react';
import Button from '../components/Button';

export default function QuizPage() {

  const [questions, setQuestions] = useState([]);
  const [selected, setSelected] = useState({});
  const [submitted, setSubmitted] = useState(false);

  const domain = localStorage.getItem("selectedDomain") || "ai-and-ml";
  const currentDay = parseInt(localStorage.getItem("currentDay") || "1");

  useEffect(() => {

    const allCompleted = JSON.parse(localStorage.getItem("dailyCompleted") || "{}");

    // 🔥 Take previous day completed topics
    const topics = allCompleted[currentDay - 1] || [];

    if (topics.length === 0) {
      setQuestions([]);
      return;
    }

    // 🔥 DOMAIN BASED QUESTION BANK
    const questionBank = {
      "ai-and-ml": {
        "Python Basics → Datatypes (int, float, string)": {
          question: "Which of the following is a valid Python datatype?",
          options: ["int", "float", "string", "All of the above"],
          answer: "All of the above"
        },
        "Variables & Input/Output": {
          question: "Which function is used for input in Python?",
          options: ["input()", "print()", "scan()", "read()"],
          answer: "input()"
        },
        "Loops (for, while)": {
          question: "Which loop runs until condition becomes false?",
          options: ["for", "while", "loop", "none"],
          answer: "while"
        },
        "Functions (def, return)": {
          question: "Which keyword defines a function in Python?",
          options: ["def", "func", "function", "define"],
          answer: "def"
        }
      },

      "web-development": {
        "HTML → Tags, Structure": {
          question: "Which tag defines a paragraph?",
          options: ["<p>", "<div>", "<span>", "<h1>"],
          answer: "<p>"
        },
        "CSS → Selectors, Box Model": {
          question: "Which property controls outer spacing?",
          options: ["margin", "padding", "border", "width"],
          answer: "margin"
        },
        "JavaScript → Variables": {
          question: "Which keyword declares variable?",
          options: ["var", "let", "const", "All"],
          answer: "All"
        }
      }
    };

    const domainQuestions = questionBank[domain] || {};

    // 🔥 Generate quiz
    const generated = topics.map((topic, index) => {
      const q = domainQuestions[topic];

      if (!q) return null;

      return {
        id: index + 1,
        ...q
      };
    }).filter(Boolean);

    setQuestions(generated);

  }, [domain, currentDay]);

  const score = questions.reduce((acc, q) => {
    return acc + (selected[q.id] === q.answer ? 1 : 0);
  }, 0);

  return (
    <div className="space-y-8">
      <div className="rounded-[2rem] border border-slate-300 bg-gradient-to-br from-white to-blue-50 p-8 shadow-lg dark:border-slate-600 dark:from-slate-800 dark:to-slate-800">

        <h2 className="text-3xl font-semibold text-slate-900 dark:text-slate-50">
          Daily Quiz
        </h2>

        <p className="mt-3 text-slate-600 dark:text-slate-300">
          Quiz based on your completed topics
        </p>

        {/* ❌ No quiz */}
        {questions.length === 0 && (
          <p className="mt-6 text-red-500">
            Complete today's tasks to unlock quiz
          </p>
        )}

        {/* ✅ Quiz */}
        <div className="mt-8 space-y-6">
          {questions.map((question) => (
            <div key={question.id} className="space-y-4 rounded-3xl border border-slate-300 bg-gradient-to-br from-blue-50 to-teal-50 p-5 dark:border-slate-600 dark:from-slate-700 dark:to-slate-700">

              <div className="text-lg font-semibold">
                {question.question}
              </div>

              <div className="grid gap-3 sm:grid-cols-2">
                {question.options.map((option) => (
                  <button
                    key={option}
                    onClick={() =>
                      setSelected(prev => ({ ...prev, [question.id]: option }))
                    }
                    className={`rounded-3xl border px-4 py-3 text-left ${
                      selected[question.id] === option
                        ? 'bg-teal-100 border-teal-400'
                        : 'bg-white hover:bg-teal-50'
                    }`}
                  >
                    {option}
                  </button>
                ))}
              </div>

            </div>
          ))}
        </div>

        {/* Submit */}
        {questions.length > 0 && (
          <div className="mt-6 flex justify-between">
            <Button onClick={() => setSubmitted(true)}>
              Submit Quiz
            </Button>

            {submitted && (
              <div className="rounded-3xl bg-teal-100 px-4 py-3 text-sm font-medium">
                Score: {score} / {questions.length}
              </div>
            )}
          </div>
        )}

      </div>
    </div>
  );
}
